const input = items[0].json; // assume que o JSON está na entrada do nó de código

// Função para remover emojis de uma string
function removeEmojis(str) {
  return str.replace(/[\u{1F600}-\u{1F64F}]/gu, '')
            .replace(/[\u{1F300}-\u{1F5FF}]/gu, '')
            .replace(/[\u{1F680}-\u{1F6FF}]/gu, '')
            .replace(/[\u{1F700}-\u{1F77F}]/gu, '')
            .replace(/[\u{1F780}-\u{1F7FF}]/gu, '')
            .replace(/[\u{1F800}-\u{1F8FF}]/gu, '')
            .replace(/[\u{1F900}-\u{1F9FF}]/gu, '')
            .replace(/[\u{1FA00}-\u{1FA6F}]/gu, '')
            .replace(/[\u{1FA70}-\u{1FAFF}]/gu, '')
            .replace(/[\u{2600}-\u{26FF}]/gu, '')
            .replace(/[\u{2700}-\u{27BF}]/gu, '');
}

// Remontando o JSON com as regras especificadas
const fieldDefinitions = input.body.form_response.definition.fields;
const answers = input.body.form_response.answers;

// Processa as respostas e extrai os dados relevantes
const processedAnswers = answers.map(answer => {
  const fieldInfo = fieldDefinitions.find(field => field.ref === answer.field.ref);
  if (fieldInfo) {
    let responseText;
    // Determinar o tipo de resposta e extrair o texto relevante
    switch (answer.type) {
      case 'text':
        responseText = answer.text;
        break;
      case 'phone_number':
        responseText = answer.phone_number;
        break;
      case 'choice':
        responseText = answer.choice.label;
        break;
      case 'email':
        responseText = answer.email;
        break;
      default:
        responseText = 'Tipo de resposta desconhecido';
    }
    return {
      id: fieldInfo.id,
      response: removeEmojis(responseText.replace(/[{}]/g, '')) // Remove '{' e '}' da resposta e emojis
    };
  }
  return null;
}).filter(item => item !== null); // Filtra itens nulos se o ref não coincidir

// Transforma o array processado em um objeto com IDs como chaves e respostas como valores
const result = processedAnswers.reduce((accumulator, currentItem) => {
  if (currentItem.id) { // Verifica se o id está definido
    accumulator[currentItem.id] = currentItem.response;
  }
  return accumulator;
}, {});

return [{ json: result }]; // Retorna o resultado formatado corretamente em um array para compatibilidade com o n8n

