  const texto = ($json.Faturamento || '')
    .toLowerCase()
    .replace(/r\$/g, '')
    .replace(/por mês|mensal|mensais|entre|de|até/g, '')
    .replace(/mil/g, 'k')
    .replace(/\s+/g, ' ')
    .trim();

  const numeros = texto.match(/\d+/g)?.map(Number);
  if (!numeros || numeros.length === 0) return null;

  const min = numeros[0];
  const max = numeros[1] || numeros[0];

  if (max <= 5) return '0 a 5k';
  if (min >= 5 && max <= 15) return '5 a 15k';
  if (min >= 15 && max <= 30) return '15 a 30k';
  if (min >= 30 && max <= 50) return '30 a 50k';
  if (min >= 50 && max <= 100) return '50 a 100k';
  if (min >= 100) return '100 a 200k';

  return null;
})()
}}

